(window.webpackJsonp=window.webpackJsonp||[]).push([[242],{869:function(n,e){n.exports='\x3c!-- \ntitle: 09-Tomcat+git+redis\nsort: \n--\x3e \n\n> `wget 192.168.25.37/download/hello-world.war`\n>\n> `tomcat`: `/var/lib/tomcat9/webapps`\n>\n> `redis-cli`\n\n## Redis\n\n> 对键值对的操纵\n>\n> `apt install redis`\n>\n> `redis-cli`\n\n```sql\n-- 添加\nset <key_name> <value>\n-- 查询\nget <key_name>\n-- 删除\ndel <key_name>\n-- 批量\nmset key1 hello key2 world\nmget key1 key2\n\n-- hash 操作\nhset hash1 name fzf age 18\nhget hash1 name\nhgetall hash1\nhdel hash1 name\n\n-- list 操作\n-- 链表\nlpush list1 value1 value2\nlrange list1 0 -1\n-- 从第0个到结尾\n\n-- set 操作\n-- 存入无法改变\nsadd set1 value1 value2\n\n-- 删库\nflushall\n-- 换库\nselect <index>\n```\n\n### 列表\n\n> 看不懂拉倒,谁叫你不来.\n\n![image-20201204183917354](https://gitee.com//nmdfzf404/Image-hosting/raw/master/2020/image-20201204183917354.png)\n\n## Tomcat\n\n> 部署war包\n\n## GIthub\n\n```bash\nCreate a new repository#\n# 初始化\ngit init\n\ngit add .\ngit commit -a -m "update"\n# 撤回提交\ngit log\ngit reset --soft|--hard <id>\n# 发送到远程仓库\ngit remote add origin <url>\ngit push -u origin master\n```\n\n\n\n'}}]);